long binary_search(const std::vector<long>& arr, long target){
  long lo=0, hi=(long)arr.size()-1;
  while(lo<=hi){
    long mid=lo+(hi-lo)/2;
    if(arr[mid]==target) return mid;
    else if(arr[mid]<target) lo=mid+1;
    else hi=mid-1;
  }
  return -1;
}

